  1	import { type FC, type FormEvent, useCallback, useState } from 'react';
  2	import { encode } from 'js-base64';
  3	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  4	import type { CredentialsEditModeByTypeProps } from 'src/providers/details/tabs/Credentials/components/utils/types';
  5	import { SecretFieldsId } from 'src/providers/utils/constants';
  6	import { useForkliftTranslation } from 'src/utils/i18n';
  7	
  8	import {
  9	  Button,
 10	  ButtonVariant,
 11	  Divider,
 12	  Form,
 13	  InputGroup,
 14	  TextInput,
 15	} from '@patternfly/react-core';
 16	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 17	import type { ValidationMsg } from '@utils/validation/Validation';
 18	
 19	import { getDecodedValue } from './utils/getDecodedValue';
 20	import { ovirtSecretFieldValidator } from './utils/ovirtSecretFieldValidator';
 21	import CertificateEditSection from './CertificateEditSection';
 22	
 23	const OvirtCredentialsEdit: FC<CredentialsEditModeByTypeProps> = ({
 24	  onNewSecretChange,
 25	  secret,
 26	}) => {
 27	  const { t } = useForkliftTranslation();
 28	
 29	  const url = getDecodedValue(secret?.data?.url);
 30	  const user = getDecodedValue(secret?.data?.user);
 31	  const password = getDecodedValue(secret?.data?.password);
 32	  const insecureSkipVerify = getDecodedValue(secret?.data?.insecureSkipVerify);
 33	  const cacert = getDecodedValue(secret?.data?.cacert);
 34	
 35	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 36	  const [userValidation, setUserValidation] = useState<ValidationMsg>(
 37	    ovirtSecretFieldValidator(SecretFieldsId.User, user!),
 38	  );
 39	  const [passwordValidation, setPasswordValidation] = useState<ValidationMsg>(
 40	    ovirtSecretFieldValidator(SecretFieldsId.Password, password!),
 41	  );
 42	  const [cacertValidation, setCacertValidation] = useState<ValidationMsg>(
 43	    ovirtSecretFieldValidator(SecretFieldsId.CaCert, cacert!),
 44	  );
 45	  const [insecureSkipVerifyValidation, setInsecureSkipVerifyValidation] = useState<ValidationMsg>(
 46	    ovirtSecretFieldValidator(SecretFieldsId.InsecureSkipVerify, insecureSkipVerify!),
 47	  );
 48	
 49	  const handleChange = useCallback(
 50	    (id: SecretFieldsId, value: string) => {
 51	      const validationState = ovirtSecretFieldValidator(id, value);
 52	
 53	      if (id === SecretFieldsId.User) setUserValidation(validationState);
 54	      if (id === SecretFieldsId.Password) setPasswordValidation(validationState);
 55	      if (id === SecretFieldsId.InsecureSkipVerify)
 56	        setInsecureSkipVerifyValidation(validationState);
 57	      if (id === SecretFieldsId.CaCert) setCacertValidation(validationState);
 58	
 59	      // don't trim fields that allow spaces
 60	      const encodedValue =
 61	        id === SecretFieldsId.CaCert ? encode(value ?? '') : encode(value?.trim() ?? '');
 62	
 63	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 64	    },
 65	    [secret, onNewSecretChange],
 66	  );
 67	
 68	  const onClickTogglePassword = () => {
 69	    setPasswordHidden(!passwordHidden);
 70	  };
 71	
 72	  const onChangeUser: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
 73	    _event,
 74	    value,
 75	  ) => {
 76	    handleChange(SecretFieldsId.User, value);
 77	  };
 78	
 79	  const onChangePassword: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
 80	    _event,
 81	    value,
 82	  ) => {
 83	    handleChange(SecretFieldsId.Password, value);
 84	  };
 85	
 86	  const onChangeInsecure: (_event: FormEvent<HTMLInputElement>, checked: boolean) => void = (
 87	    _event,
 88	    checked,
 89	  ) => {
 90	    handleChange(SecretFieldsId.InsecureSkipVerify, checked ? 'true' : 'false');
 91	  };
 92	
 93	  const onDataChange: (data: string) => void = (data) => {
 94	    handleChange(SecretFieldsId.CaCert, data);
 95	  };
 96	
 97	  return (
 98	    <Form isWidthLimited className="forklift-section-secret-edit">
 99	      <FormGroupWithHelpText
100	        label={t('Username')}
101	        isRequired
102	        fieldId="user"
103	        helperText={userValidation.msg}
104	        helperTextInvalid={userValidation.msg}
105	        validated={userValidation.type}
106	      >
107	        <TextInput
108	          spellCheck="false"
109	          isRequired
110	          type="text"
111	          id="user"
112	          name="user"
113	          value={user}
114	          validated={userValidation.type}
115	          onChange={onChangeUser}
116	        />
117	      </FormGroupWithHelpText>
118	      <FormGroupWithHelpText
119	        label={t('Password')}
120	        isRequired
121	        fieldId="password"
122	        helperText={passwordValidation.msg}
123	        helperTextInvalid={passwordValidation.msg}
124	        validated={passwordValidation.type}
125	      >
126	        <InputGroup>
127	          <TextInput
128	            spellCheck="false"
129	            isRequired
130	            type={passwordHidden ? 'password' : 'text'}
131	            aria-label="Password input"
132	            value={password}
133	            validated={passwordValidation.type}
134	            onChange={onChangePassword}
135	          />
136	          <Button
137	            variant={ButtonVariant.control}
138	            onClick={onClickTogglePassword}
139	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
140	          >
141	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
142	          </Button>
143	        </InputGroup>
144	      </FormGroupWithHelpText>
145	
146	      <Divider />
147	      <CertificateEditSection
148	        insecureSkipVerifyValidation={insecureSkipVerifyValidation}
149	        insecureSkipVerify={insecureSkipVerify}
150	        cacertValidation={cacertValidation}
151	        cacert={cacert}
152	        url={url}
153	        onChangeInsecure={onChangeInsecure}
154	        onDataChange={onDataChange}
155	      />
156	    </Form>
157	  );
158	};
159	
160	export default OvirtCredentialsEdit;

